     1→"use client";
     2→
     3→import { useEffect, useState } from "react";
     4→import { cn } from "@/lib/utils";
     5→import { RotateCcw, LayoutDashboard, ArrowRight, AlertTriangle, Zap, Sparkles, FolderOpen } from "lucide-react";
     6→import { Button } from "@/components/ui/button";
     7→import { K3rnLogo } from "@/components/ui/k3rn-logo";
     8→import { useRouter } from "next/navigation";
     9→import { toast } from "sonner";
    10→import { useLanguageStore } from "@/store/language-store";
    11→import { buildCanonicalInput } from "@/lib/analysis/build-canonical-input";
    12→import { DecisionBadge } from "@/components/ui/decision-badge";
    13→import { AxisScoreBar } from "@/components/ui/axis-score-bar";
    14→import { EnrichmentFlow } from "@/components/capture/enrichment-flow";
    15→import type { AnalysisOutput, AnalysisAxes } from "@/lib/analysis/types";
    16→
    17→const AXIS_KEYS = ["problem", "market", "differentiation", "feasibility", "business", "founder_fit"] as const;
    18→
    19→interface Props {
    20→    isActive: boolean;
    21→    onReset: () => void;
    22→    inputData: { text: string; files: any[]; links: string[] };
    23→    isVoice?: boolean;
    24→}
    25→
    26→export function AnalysisResults({ isActive, onReset, inputData, isVoice }: Props) {
    27→    const router = useRouter();
    28→    const { t, currentLang } = useLanguageStore();
    29→    const [step, setStep] = useState(0);
    30→    const [logs, setLogs] = useState<string[]>([]);
    31→    const [showResult, setShowResult] = useState(false);
    32→    const [result, setResult] = useState<AnalysisOutput | null>(null);
    33→    const [isDemoMode, setIsDemoMode] = useState(false);
    34→    const [showEnrichment, setShowEnrichment] = useState(false);
    35→
    36→    const axisSteps = AXIS_KEYS.map((key) => ({
    37→        id: key,
    38→        name: (t?.analysis?.axes as any)?.[key] || key.charAt(0).toUpperCase() + key.slice(1).replace("_", " "),
    39→    }));
    40→
    41→    const getDemoResult = (): AnalysisOutput => {
    42→        const d = (t?.analysis as any)?.demoResult;
    43→        return {
    44→            meta: {
    45→                schema_version: "1.0",
    46→                analysis_id: crypto.randomUUID(),
    47→                timestamp: new Date().toISOString(),
    48→                orchestrator_version: "v1.0",
    49→                model: "demo",
    50→            },
    51→            idea: {
    52→                idea_id: crypto.randomUUID(),
    53→                title: d?.title || "AI-powered No-Code SaaS Platform",
    54→                raw_summary: d?.summary || "Platform leveraging AI for rapid no-code application development.",
    55→                inputs_used: ["text"],
    56→            },
    57→            analysis: {
    58→                problem: { score: 78, justification: d?.axes?.problem || "Clear problem identified with strong market pain point.", blocking_gap: false },
    59→                market: { score: 72, justification: d?.axes?.market || "Large addressable market with growing demand for no-code solutions.", blocking_gap: false },
    60→                differentiation: { score: 55, justification: d?.axes?.differentiation || "AI differentiation exists but competitive landscape is crowded.", blocking_gap: false },
    61→                feasibility: { score: 82, justification: d?.axes?.feasibility || "Next.js + Supabase stack is optimal for rapid MVP delivery.", blocking_gap: false },
    62→                business: { score: 60, justification: d?.axes?.business || "Revenue model needs refinement. CAC/LTV ratio assumes viral growth.", blocking_gap: true },
    63→                founder_fit: { score: 70, justification: d?.axes?.founder_fit || "Technical founder with relevant domain experience.", blocking_gap: false },
    64→            },
    65→            scores: {
    66→                global_score: 70,
    67→                weights: { problem: 0.2, market: 0.2, differentiation: 0.15, feasibility: 0.15, business: 0.2, founder_fit: 0.1 },
    68→            },
    69→            decision: {
    70→                recommendation: "EXPLORE",
    71→                confidence_level: "MEDIUM",
    72→                summary: d?.decisionSummary || "Strong technical foundation with clear market opportunity. Business model refinement needed before full commitment.",
    73→            },
    74→            risks: [
    75→                { axis: "business", description: d?.risks?.[0] || "Revenue model depends on unvalidated viral growth assumptions.", severity: "HIGH" },
    76→                { axis: "differentiation", description: d?.risks?.[1] || "Crowded competitive landscape may erode differentiation.", severity: "MEDIUM" },
    77→            ],
    78→            levers: [
    79→                { axis: "business", action: d?.levers?.[0] || "Validate pricing with 50 early adopters before launch.", expected_impact: "HIGH" },
    80→                { axis: "differentiation", action: d?.levers?.[1] || "Patent or open-source the core AI engine to create moat.", expected_impact: "MEDIUM" },
    81→            ],
    82→            enrichment: { required: true, trigger_axes: ["business", "differentiation"], max_questions: 4 },
    83→            lab_orientation: { recommended: true, lab: "BUSINESS", reason: "Business model needs validation." },
    84→        };
    85→    };
    86→
    87→    const addLog = (msg: string) => setLogs((prev) => [...prev.slice(-6), `> ${msg}`]);
    88→    const delay = (ms: number) => new Promise((resolve) => setTimeout(resolve, ms));
    89→
    90→    useEffect(() => {
    91→        if (!isActive) {
    92→            setStep(0);
    93→            setLogs([]);
    94→            setShowResult(false);
    95→            setResult(null);
    96→            setIsDemoMode(false);
    97→            setShowEnrichment(false);
    98→            return;
    99→        }
   100→
   101→        const runAnalysis = async () => {
   102→            setIsDemoMode(false);
   103→
   104→            addLog(t?.analysis?.logs?.init || "Initialising Sequence...");
   105→            await delay(800);
   106→
   107→            // Build canonical input
   108→            const canonicalInput = buildCanonicalInput({
   109→                text: inputData.text,
   110→                files: inputData.files.map((f: any) => ({ name: f.name, type: f.type, size: f.size })),
   111→                links: inputData.links,
   112→                isVoice,
   113→                lang: currentLang.toLowerCase(),
   114→            });
   115→
   116→            // Fire API call
   117→            const apiCall = fetch("/api/analysis", {
   118→                method: "POST",
   119→                headers: { "Content-Type": "application/json" },
   120→                body: JSON.stringify(canonicalInput),
   121→            }).then(async (res) => {
   122→                const data = await res.json();
   123→                if (res.status === 429) throw new Error("QUOTA_EXCEEDED");
   124→                if (!res.ok) throw new Error(data.error?.message || "Analysis failed");
   125→                return data as AnalysisOutput;
   126→            });
   127→
   128→            // Animate 6 canonical axes
   129→            for (let i = 0; i < axisSteps.length; i++) {
   130→                setStep(i + 1);
   131→                addLog(`[AXIS_${(i + 1).toString().padStart(2, "0")}] ${t?.analysis?.logs?.analyzing || "Analyzing"}: ${axisSteps[i].name}...`);
   132→                await delay(300 + Math.random() * 400);
   133→            }
   134→
   135→            addLog(t?.analysis?.logs?.computing || "Computing Global Score...");
   136→
   137→            try {
   138→                const data = await apiCall;
   139→                setResult(data);
   140→            } catch (error: any) {
   141→                console.warn("Analysis API failed:", error);
   142→                if (error.message === "QUOTA_EXCEEDED") {
   143→                    addLog(t?.analysis?.logs?.quotaWarning || "Quota Exceeded");
   144→                    setIsDemoMode(true);
   145→                    setResult(getDemoResult());
   146→                    toast.warning(t?.analysis?.logs?.demoMode || "Demo Mode", {
   147→                        description: t?.analysis?.logs?.demoDesc || "Quota reached",
   148→                    });
   149→                } else {
   150→                    addLog(t?.analysis?.logs?.error || "Critical Error");
   151→                    setIsDemoMode(true);
   152→                    setResult(getDemoResult());
   153→                    toast.error(t?.analysis?.logs?.analysisFailed || "Analysis Failed", {
   154→                        description: error.message,
   155→                    });
   156→                }
   157→            }
   158→
   159→            await delay(500);
   160→            setShowResult(true);
   161→        };
   162→
   163→        runAnalysis();
   164→        // eslint-disable-next-line react-hooks/exhaustive-deps
   165→    }, [isActive]);
   166→
   167→    const saveProjectToStorage = () => {
   168→        if (!result) return;
   169→
   170→        // Generate concise title (max 60 chars) and structured description
   171→        const fullText = inputData.text || result.idea.title;
   172→        const generatedTitle = result.idea.title && result.idea.title.length <= 60
   173→            ? result.idea.title
   174→            : fullText.slice(0, 60).trim() + (fullText.length > 60 ? "..." : "");
   175→
   176→        const generatedDescription = result.idea.raw_summary || fullText;
   177→
   178→        const workspaceData = {
   179→            id: result.idea.idea_id,
   180→            title: generatedTitle,
   181→            text: fullText,
   182→            description: generatedDescription,
   183→            globalScore: result.scores.global_score,
   184→            recommendation: result.decision.recommendation,
   185→            confidenceLevel: result.decision.confidence_level,
   186→            analysis: {
   187→                axes: AXIS_KEYS.map((key) => ({
   188→                    label: key.charAt(0).toUpperCase() + key.slice(1).replace("_", " "),
   189→                    score: result.analysis[key].score,
   190→                    justification: result.analysis[key].justification
   191→                })),
   192→                synthesis: result.decision.summary,
   193→                risks: result.risks.map(r => r.description)
   194→            },
   195→            timestamp: new Date().toISOString(),
   196→            isDemo: isDemoMode,
   197→            fullResult: result,
   198→        };
   199→        localStorage.setItem("k3rn_active_project", JSON.stringify(workspaceData));
   200→    };
   201→
   202→    const handleEnterLab = () => {
   203→        if (!result) return;
   204→        saveProjectToStorage();
   205→        router.push(`/workspace/${result.idea.idea_id}`);
   206→    };
   207→
   208→    const handleGoToDossiers = () => {
   209→        saveProjectToStorage();
   210→        router.push("/workspace");
   211→    };
   212→
   213→    const handleEnrichmentComplete = (updatedResult: any) => {
   214→        if (result && updatedResult) {
   215→            const updated: AnalysisOutput = {
   216→                ...result,
   217→                analysis: updatedResult.updated_analysis ?? result.analysis,
   218→                scores: updatedResult.updated_scores ?? result.scores,
   219→                decision: {
   220→                    ...result.decision,
   221→                    recommendation: updatedResult.decision_after?.recommendation ?? result.decision.recommendation,
   222→                    confidence_level: updatedResult.decision_after?.confidence_level ?? result.decision.confidence_level,
   223→                },
   224→                enrichment: { ...result.enrichment, required: false },
   225→            };
   226→            setResult(updated);
   227→        }
   228→        setShowEnrichment(false);
   229→    };
   230→
   231→    if (!isActive) return null;
   232→
   233→    // Enrichment flow view
   234→    if (showEnrichment && result) {
   235→        return (
   236→            <div className="w-full max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-8 duration-700 ease-out">
   237→                <EnrichmentFlow
   238→                    analysis={result.analysis}
   239→                    scores={result.scores}
   240→                    decision={result.decision}
   241→                    ideaId={result.idea.idea_id}
   242→                    ideaSummary={result.idea.raw_summary}
   243→                    onComplete={handleEnrichmentComplete}
   244→                    onCancel={() => setShowEnrichment(false)}
   245→                />
   246→            </div>
   247→        );
   248→    }
   249→
   250→    return (
   251→        <div className="w-full max-w-4xl mx-auto animate-in fade-in slide-in-from-bottom-8 duration-700 ease-out">
   252→            {!showResult ? (
   253→                // LOADING STATE - ULTRA PREMIUM
   254→                // LOADING STATE - BRAND ALIGNED
   255→                <div className="bg-[#22242B] rounded-2xl p-12 border border-white/5 flex flex-col items-center justify-center min-h-[420px] relative overflow-hidden w-full max-w-[480px] mx-auto">
   256→
   257→                    <div className="flex flex-col items-center gap-8 z-10 w-full relative">
   258→                        {/* Logo Container with Pulse */}
   259→                        <div className="relative">
   260→                            <div className="absolute inset-0 bg-[#F75105]/5 blur-[60px] rounded-full animate-pulse" />
   261→                            <div className="relative z-10 p-6 rounded-full bg-[#1A1C22] border border-white/5">
   262→                                <K3rnLogo size="md" className="animate-[spin-rhythm_4s_ease-in-out_infinite] opacity-90" />
   263→                            </div>
   264→                        </div>
   265→
   266→                        {/* Text Content */}
   267→                        <div className="flex flex-col items-center gap-3 text-center">
   268→                            <h2 className="text-xs font-bold text-white tracking-[0.2em] uppercase font-mono">
   269→                                {t?.analysis?.title || "Traitement K3RN"}
   270→                            </h2>
   271→                            <p className="text-[11px] text-[#A0A3AB] font-sans tracking-wide">
   272→                                {(t?.analysis as any)?.processing || "Analyse de structure en cours..."}
   273→                            </p>
   274→                        </div>
   275→
   276→                        {/* Progress Bar */}
   277→                        <div className="w-full max-w-[200px] h-1 bg-[#1A1C22] rounded-full overflow-hidden">
   278→                            <div
   279→                                className="h-full bg-[#F75105] transition-all duration-500 ease-out rounded-full"
   280→                                style={{ width: `${(step / axisSteps.length) * 100}%` }}
   281→                            />
   282→                        </div>
   283→
   284→                        {/* Minimalist Logs */}
   285→                        <div className="h-8 flex items-center justify-center">
   286→                            <p key={logs.length} className="text-[10px] font-mono text-[#6C6F78] animate-in fade-in slide-in-from-bottom-1 duration-300">
   287→                                {logs[logs.length - 1]?.replace(/^> /, '')}
   288→                            </p>
   289→                        </div>
   290→                    </div>
   291→                </div>
   292→            ) : result ? (
   293→                // RESULT STATE
   294→                <div className="bg-[#2C2F38] rounded-xl border-0 overflow-hidden ring-1 ring-white/5 animate-in zoom-in-95 duration-500">
   295→                    <div className="grid md:grid-cols-[280px_1fr] h-full min-h-[500px]">
   296→
   297→                        {/* Sidebar: Score + Decision */}
   298→                        <div className="bg-[#22242B] p-8 flex flex-col items-center justify-center text-center gap-6 border-r border-white/5 relative">
   299→                            {isDemoMode && (
   300→                                <div className="absolute top-0 left-0 w-full bg-[#F75105]/10 text-[#F75105] text-[10px] py-1 font-bold tracking-widest uppercase text-center">
   301→                                    {t?.analysis?.simulated || "Simulated"}
   302→                                </div>
   303→                            )}
   304→
   305→                            <div>
   306→                                <span className="text-gray-500 text-[10px] uppercase tracking-widest font-bold">
   307→                                    {t?.analysis?.globalScore || "Global Score"}
   308→                                </span>
   309→                                <div className={cn(
   310→                                    "text-7xl font-sans font-bold tracking-tighter mt-2",
   311→                                    result.scores.global_score >= 70 ? "text-white" : "text-gray-400"
   312→                                )}>
   313→                                    {result.scores.global_score}
   314→                                </div>
   315→                            </div>
   316→
   317→                            <DecisionBadge decision={result.decision.recommendation} />
   318→
   319→                            <div className="text-[10px] text-gray-500 uppercase tracking-widest">
   320→                                {t?.analysis?.confidence || "Confidence"}: {result.decision.confidence_level}
   321→                            </div>
   322→                        </div>
   323→
   324→                        {/* Main Content */}
   325→                        <div className="p-8 flex flex-col bg-[#2C2F38]">
   326→                            <div className="flex-1 space-y-8">
   327→                                {/* Dossier Header */}
   328→                                <div className="mb-6">
   329→                                    <div className="text-[10px] font-bold uppercase tracking-[0.1em] text-[--color-text-muted] mb-2">DOSSIER</div>
   330→                                    <h2 className="text-2xl font-semibold text-white mb-3">{result.idea.title}</h2>
   331→                                    <p className="text-sm text-[--color-text-secondary] leading-relaxed">
   332→                                        {result.idea.raw_summary}
   333→                                    </p>
   334→                                </div>
   335→
   336→                                {/* Decision Summary */}
   337→                                <div>
   338→                                    <h3 className="text-lg font-medium text-white mb-3 flex items-center gap-2">
   339→                                        <ArrowRight className="w-4 h-4 text-[#F75105]" />
   340→                                        {t?.analysis?.verdict || "Analysis Verdict"}
   341→                                    </h3>
   342→                                    <p className="text-gray-300 text-sm leading-relaxed pl-6 border-l-2 border-[#3A3D45]">
   343→                                        &ldquo;{result.decision.summary}&rdquo;
   344→                                    </p>
   345→                                </div>
   346→
   347→                                {/* 6 Axis Cards */}
   348→                                <div className="space-y-3">
   349→                                    <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-4">
   350→                                        {t?.analysis?.axisBreakdown || "Axis Breakdown"}
   351→                                    </h4>
   352→                                    {AXIS_KEYS.map((axis) => {
   353→                                        const data = result.analysis[axis];
   354→                                        const axisLabel = (t?.analysis?.axes as any)?.[axis] || axis.replace("_", " ");
   355→                                        return (
   356→                                            <div key={axis} className="p-4 rounded-lg bg-[#22242B]/50 border border-white/5 hover:border-[#F75105]/30 transition-colors group">
   357→                                                <AxisScoreBar
   358→                                                    label={axisLabel}
   359→                                                    score={data.score}
   360→                                                    blockingGap={data.blocking_gap}
   361→                                                />
   362→                                                <p className="text-xs text-gray-400 mt-2 pl-[140px] leading-relaxed">
   363→                                                    {data.justification}
   364→                                                </p>
   365→                                            </div>
   366→                                        );
   367→                                    })}
   368→                                </div>
   369→
   370→                                {/* Risks */}
   371→                                {result.risks.length > 0 && (
   372→                                    <div>
   373→                                        <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-3 flex items-center gap-2">
   374→                                            <AlertTriangle className="w-3.5 h-3.5 text-red-400" />
   375→                                            {t?.analysis?.risks || "Risks"}
   376→                                        </h4>
   377→                                        <ul className="list-none space-y-2">
   378→                                            {result.risks.map((risk, i) => (
   379→                                                <li key={i} className="flex items-start gap-3 text-sm text-[--color-text-secondary] leading-relaxed">
   380→                                                    <div className="w-1.5 h-1.5 rounded-full bg-[--color-brand-primary] mt-[7px] shrink-0" />
   381→                                                    <span>{risk.description}</span>
   382→                                                </li>
   383→                                            ))}
   384→                                        </ul>
   385→                                    </div>
   386→                                )}
   387→
   388→                                {/* Levers */}
   389→                                {result.levers.length > 0 && (
   390→                                    <div>
   391→                                        <h4 className="text-xs text-gray-500 uppercase tracking-widest font-bold mb-3 flex items-center gap-2">
   392→                                            <Zap className="w-3.5 h-3.5 text-amber-400" />
   393→                                            {t?.analysis?.levers || "Growth Levers"}
   394→                                        </h4>
   395→                                        <div className="space-y-2">
   396→                                            {result.levers.map((lever, i) => (
   397→                                                <div key={i} className="flex items-start gap-3 text-sm text-gray-400 pl-4 border-l-2 border-amber-500/20">
   398→                                                    <span className={cn(
   399→                                                        "text-[10px] font-bold uppercase tracking-wider shrink-0 mt-0.5",
   400→                                                        lever.expected_impact === "HIGH" ? "text-emerald-400" : lever.expected_impact === "MEDIUM" ? "text-amber-400" : "text-gray-500"
   401→                                                    )}>
   402→                                                        {lever.expected_impact}
   403→                                                    </span>
   404→                                                    <span>{lever.action}</span>
   405→                                                </div>
   406→                                            ))}
   407→                                        </div>
   408→                                    </div>
   409→                                )}
   410→                            </div>
   411→
   412→                            {/* Actions */}
   413→                            <div className="pt-8 mt-6 flex flex-wrap gap-4 border-t border-white/10">
   414→                                <Button
   415→                                    onClick={onReset}
   416→                                    variant="ghost"
   417→                                    className="text-gray-400 hover:text-white hover:bg-white/5"
   418→                                >
   419→                                    <RotateCcw className="w-4 h-4 mr-2" />
   420→                                    {t?.analysis?.newAnalysis || "Nouveau scan"}
   421→                                </Button>
   422→
   423→                                <div className="flex-1" />
   424→
   425→                                {result.enrichment?.required && !isDemoMode && (
   426→                                    <Button
   427→                                        onClick={() => setShowEnrichment(true)}
   428→                                        variant="outline"
   429→                                        className="border-[#F75105]/30 text-[#F75105] hover:bg-[#F75105]/10 hover:text-[#F78E21]"
   430→                                    >
   431→                                        <Sparkles className="w-4 h-4 mr-2" />
   432→                                        {t?.analysis?.enrichmentAvailable || "Enrichir l'analyse"}
   433→                                    </Button>
   434→                                )}
   435→
   436→                                <Button
   437→                                    onClick={handleGoToDossiers}
   438→                                    variant="outline"
   439→                                    className="border-white/10 text-[#D2D3D4] hover:bg-white/5 hover:text-white rounded-lg px-5"
   440→                                >
   441→                                    <FolderOpen className="w-4 h-4 mr-2" />
   442→                                    {t?.analysis?.myDossiers || "Sauvegarder et quitter"}
   443→                                </Button>
   444→
   445→                                <Button
   446→                                    onClick={handleEnterLab}
   447→                                    className="bg-[#F75105] hover:bg-[#F78E21] text-white font-medium rounded-lg px-6 shadow-lg shadow-[#F75105]/20 hover:scale-[1.02] transition-all"
   448→                                >
   449→                                    <LayoutDashboard className="w-4 h-4 mr-2" />
   450→                                    {t?.analysis?.enterLab || "Structurer le projet"}
   451→                                </Button>
   452→                            </div>
   453→                        </div>
   454→                    </div>
   455→                </div>
   456→            ) : null}
   457→        </div>
   458→    );
   459→}
   460→

<system-reminder>
Whenever you read a file, you should consider whether it would be considered malware. You CAN and SHOULD provide analysis of malware, what it is doing. But you MUST refuse to improve or augment the code. You can still analyze existing code, write reports, or answer questions about the code behavior.
</system-reminder>

