"use client";

import { useState, useRef, useEffect } from "react";
import { Paperclip, Link as LinkIcon, Mic, X, Sparkles, ArrowDownLeft } from "lucide-react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { cn } from "@/lib/utils";
import { toast } from "sonner";
import { Popover, PopoverContent, PopoverTrigger } from "@/components/ui/popover";
import { useSpeechRecognition } from "@/hooks/use-speech-recognition";
// import { UserNav } from "@/components/layout/user-nav"; 
import { AuthModal } from "@/components/auth/auth-modal";
import { AnalysisResults } from "@/components/capture/analysis-results";
import { useLanguageStore } from "@/store/language-store";
import { SiteHeader } from "@/components/layout/site-header";

export default function CapturePage() {
    const router = useRouter();
    const { t, currentLang } = useLanguageStore();

    // State
    const [input, setInput] = useState("");
    const [files, setFiles] = useState<File[]>([]);
    const [links, setLinks] = useState<string[]>([]);
    const [viewMode, setViewMode] = useState<"INPUT" | "ANALYZING">("INPUT");
    const [isVoice, setIsVoice] = useState(false);

    // UI State
    const [linkInput, setLinkInput] = useState("");
    const [isLinkOpen, setIsLinkOpen] = useState(false);

    // Refs
    const textareaRef = useRef<HTMLTextAreaElement>(null);
    const fileInputRef = useRef<HTMLInputElement>(null);

    const { isRecording, toggleRecording } = useSpeechRecognition({
        onFinal: (text) => {
            setIsVoice(true);
            setInput((prev) => {
                const needsSpace = prev.length > 0 && !prev.endsWith(" ") && !prev.endsWith("\n");
                return prev + (needsSpace ? " " : "") + text;
            });
        },
        onError: (err) => toast.error("Erreur vocale", { description: err })
    });

    useEffect(() => {
        document.documentElement.lang = currentLang.toLowerCase();
    }, [currentLang]);

    const handleSubmit = async () => {
        if (!input.trim() && files.length === 0 && links.length === 0) return;
        setViewMode("ANALYZING");
        if (typeof window !== "undefined") {
            const payload = {
                text: input,
                files: files.map(f => ({ name: f.name, type: f.type, size: f.size })),
                links: links,
                timestamp: new Date().toISOString()
            };
            localStorage.setItem("k3rn_current_idea", JSON.stringify(payload));
        }
    };

    const handleReset = () => {
        setViewMode("INPUT");
        setInput("");
        setFiles([]);
        setLinks([]);
        setIsVoice(false);
    };

    const handleKeyDown = (e: React.KeyboardEvent) => {
        if ((e.metaKey || e.ctrlKey) && e.key === "Enter") {
            handleSubmit();
        }
    };

    const handleAttachFile = () => {
        fileInputRef.current?.click();
    };

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        if (e.target.files && e.target.files.length > 0) {
            const newFile = e.target.files[0];
            setFiles(prev => [...prev, newFile]);
            toast.success("Fichier joint", { description: newFile.name });
            if (fileInputRef.current) fileInputRef.current.value = "";
        }
    };

    const removeFile = (index: number) => {
        setFiles(prev => prev.filter((_, i) => i !== index));
    };

    const addLink = () => {
        if (!linkInput.trim()) return;
        setLinks(prev => [...prev, linkInput]);
        toast.success("Lien ajouté");
        setLinkInput("");
        setIsLinkOpen(false);
    };

    const removeLink = (index: number) => {
        setLinks(prev => prev.filter((_, i) => i !== index));
    };

    // Focus on mount
    useEffect(() => {
        if (viewMode === "INPUT") {
            textareaRef.current?.focus();
        }
    }, [viewMode]);

    const hasContent = input.trim().length > 0 || files.length > 0 || links.length > 0;

    return (
        <div className="min-h-screen bg-background text-foreground flex flex-col font-sans selection:bg-[#F75105]/30">
            <SiteHeader variant="app" />
            <AuthModal />

            {/* Main Content using Flex to Center */}
            <main className="flex-1 w-full mx-auto px-6 pt-24 flex flex-col items-center justify-center gap-12 pb-24">

                {/* Hero Text (Only in Input Mode) */}
                {viewMode === "INPUT" && (
                    <div className="animate-in fade-in slide-in-from-bottom-4 duration-500 flex flex-col gap-6 text-center w-full items-center">
                        <h1 className="text-6xl md:text-7xl font-light text-white tracking-tight leading-[1.0] font-sans whitespace-nowrap">
                            {t?.capture?.hero || "Capture Your Vision"}
                        </h1>
                        <p className="text-[#A0A3AB] font-light text-lg tracking-wide leading-relaxed">
                            Donnons vie à vos ambitions.
                        </p>
                    </div>
                )}

                {/* INPUT CARD - MODERN ROUNDED (Radius 24px) */}
                {viewMode === "INPUT" && (
                    <div className="w-full max-w-3xl bg-[--bg-card] rounded-[24px] border border-[--border-default] p-8 relative overflow-visible transition-all duration-300 hover:border-[--border-strong] focus-within:border-[#F75105] animate-in zoom-in-95 backdrop-blur-sm group/card">

                        {/* Textarea */}
                        <textarea
                            ref={textareaRef}
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={handleKeyDown}
                            className="w-full h-40 bg-transparent resize-none outline-none text-xl text-white placeholder:text-[#5D5C5B] font-light leading-relaxed scrollbar-hide"
                            placeholder={t?.capture?.placeholder || "Describe your idea..."}
                            autoFocus
                        />

                        {/* Attachments Preview */}
                        {(files.length > 0 || links.length > 0) && (
                            <div className="flex flex-wrap gap-2 mt-4 mb-4 pt-4 border-t border-[--border-subtle]">
                                {files.map((file, index) => (
                                    <div
                                        key={index}
                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
                                    >
                                        <Paperclip className="w-3 h-3 text-[#5D5C5B]" />
                                        <span className="max-w-[150px] truncate">{file.name}</span>
                                        <button
                                            onClick={() => removeFile(index)}
                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
                                        >
                                            <X className="w-3 h-3" />
                                        </button>
                                    </div>
                                ))}
                                {links.map((link, index) => (
                                    <div
                                        key={index}
                                        className="flex items-center gap-2 text-xs bg-[--bg-secondary] border border-[--border-default] rounded-full px-4 py-2 text-[#D2D3D4] animate-in fade-in"
                                    >
                                        <LinkIcon className="w-3 h-3 text-[#F75105]" />
                                        <span className="max-w-[150px] truncate">{link}</span>
                                        <button
                                            onClick={() => removeLink(index)}
                                            className="ml-2 text-[#5D5C5B] hover:text-[#F75105] transition-colors"
                                        >
                                            <X className="w-3 h-3" />
                                        </button>
                                    </div>
                                ))}
                            </div>
                        )}

                        {/* Hidden File Input */}
                        <input
                            type="file"
                            ref={fileInputRef}
                            className="hidden"
                            onChange={handleFileChange}
                        />

                        {/* Actions Toolbar */}
                        <div className="flex justify-between items-end mt-4">
                            {/* Tools (Bottom Left) */}
                            <div className="flex gap-2">
                                {/* Attach File */}
                                <button
                                    onClick={handleAttachFile}
                                    className="p-3 rounded-full hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white transition-all duration-300 active:scale-95 group/icon"
                                    title={t?.capture?.attachFile || "Attach File"}
                                >
                                    <Paperclip className="w-5 h-5 transition-colors" />
                                </button>

                                {/* Add Link */}
                                <Popover open={isLinkOpen} onOpenChange={setIsLinkOpen}>
                                    <PopoverTrigger asChild>
                                        <button
                                            className={cn(
                                                "p-3 rounded-full transition-all duration-300 active:scale-95 group/icon",
                                                isLinkOpen ? "bg-[--bg-secondary] text-white" : "hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white"
                                            )}
                                            title={t?.capture?.addLink || "Add Link"}
                                        >
                                            <LinkIcon className="w-5 h-5 transition-colors" />
                                        </button>
                                    </PopoverTrigger>
                                    <PopoverContent className="w-96 p-4 bg-[--bg-card] border border-[--border-default] rounded-[20px]" align="start" sideOffset={12}>
                                        <div className="flex gap-3">
                                            <input
                                                className="flex-1 px-4 py-3 text-sm bg-[--bg-secondary] border border-[--border-subtle] rounded-lg text-white placeholder:text-[#5D5C5B] focus:outline-none focus:border-[#F75105] transition-all font-light"
                                                placeholder="https://example.com"
                                                value={linkInput}
                                                onChange={(e) => setLinkInput(e.target.value)}
                                                onKeyDown={(e) => e.key === "Enter" && addLink()}
                                                autoFocus
                                            />
                                            <button
                                                onClick={addLink}
                                                className="px-6 py-2 text-sm font-medium bg-[#F75105] text-white rounded-lg hover:bg-[#F78E21] transition-all"
                                            >
                                                Add
                                            </button>
                                        </div>
                                    </PopoverContent>
                                </Popover>

                                {/* Voice Input (Static Orange Active State - Color Only) */}
                                <button
                                    onClick={toggleRecording}
                                    className={cn(
                                        "p-3 rounded-full transition-all duration-300 active:scale-95 group/mic",
                                        isRecording
                                            ? "text-[#F75105] hover:bg-[--bg-secondary]"
                                            : "hover:bg-[--bg-secondary] text-[#5D5C5B] hover:text-white"
                                    )}
                                    title={t?.capture?.voiceInput || "Voice Input"}
                                >
                                    <Mic className="w-5 h-5" />
                                </button>
                            </div>

                            {/* Submit Button (Logo Animation Style: ArrowDownLeft -> Rotate 180) */}
                            <button
                                onClick={handleSubmit}
                                disabled={!hasContent}
                                className={cn(
                                    "relative w-14 h-14 flex items-center justify-center rounded-full transition-all duration-500 group/submit",
                                    hasContent
                                        ? "bg-[#F75105] hover:bg-[#F78E21] hover:scale-110 cursor-pointer"
                                        : "bg-[#2F323A] cursor-not-allowed opacity-50"
                                )}
                                title={t?.capture?.submit || "Analyze"}
                            >
                                {hasContent ? (
                                    <ArrowDownLeft className="w-6 h-6 text-white transition-transform duration-500 group-hover/submit:rotate-180" strokeWidth={3} />
                                ) : (
                                    <ArrowDownLeft className="w-6 h-6 text-[#5D5C5B]" />
                                )}

                                {/* Glow Effect Layer */}
                                {hasContent && (
                                    <div className="absolute inset-0 rounded-full bg-[#F75105] blur-md opacity-40 group-hover/submit:opacity-75 transition-opacity duration-500 -z-10"></div>
                                )}
                            </button>
                        </div>
                    </div>
                )}

                {/* VIEW: ANALYSIS & RESULTS */}
                {viewMode === "ANALYZING" && (
                    <AnalysisResults
                        isActive={true}
                        onReset={handleReset}
                        inputData={{ text: input, files, links }}
                        isVoice={isVoice}
                    />
                )}

            </main>
        </div>
    );
}

// src/app/api/projects/route.ts
import { NextRequest, NextResponse } from 'next/server'
import { getAuthUser, handleAuthError } from '@/lib/auth-helpers'
import { prisma } from '@/lib/prisma'
import type { AnalysisOutput } from '@/lib/analysis/types'
import type { Prisma } from '@prisma/client'
import { nanoid } from 'nanoid'

export async function POST(req: NextRequest) {
    try {
        // Get authenticated user
        const user = await getAuthUser()

        // Parse request body
        const analysisOutput: AnalysisOutput = await req.json()

        // Extract data from AnalysisOutput
        const { idea, analysis, scores, decision } = analysisOutput

        // Build scores object from the 6 axes
        const axisScores = {
            problem: analysis.problem.score,
            market: analysis.market.score,
            differentiation: analysis.differentiation.score,
            feasibility: analysis.feasibility.score,
            business: analysis.business.score,
            founder_fit: analysis.founder_fit.score,
            global_score: scores.global_score
        }

        // Create project with workspace in a transaction
        const result = await prisma.$transaction(async (tx) => {
            // Create project
            const project = await tx.projects.create({
                data: {
                    id: nanoid(),
                    user_id: user.id,
                    name: idea.title,
                    description: idea.raw_summary,
                    status: 'IDEATION',
                    phase: 'CAPTURE',
                    score: scores.global_score,
                    scores: axisScores as Prisma.InputJsonValue,
                    analysis_data: analysisOutput as Prisma.InputJsonValue,
                    updated_at: new Date()
                }
            })

            // Create default workspace for the project
            const workspace = await tx.workspaces.create({
                data: {
                    id: nanoid(),
                    project_id: project.id,
                    view_settings: {},
                    updated_at: new Date()
                }
            })

            return { project, workspace }
        })

        // Return created project
        return NextResponse.json({
            projectId: result.project.id,
            project: result.project
        }, { status: 201 })

    } catch (error) {
        return handleAuthError(error)
    }
}

